// Group chapters by part
const getParts = () => {
  const parts = {};
  BOOK.chapters.forEach(ch => {
    if (!parts[ch.part]) parts[ch.part] = [];
    parts[ch.part].push(ch);
  });
  return parts;
};

const fmtTime = () => {
  const d = new Date();
  return `${d.getHours().toString().padStart(2,"0")}:${d.getMinutes().toString().padStart(2,"0")}`;
};

export default function App() {
  const [view, setView] = useState("reader"); // "reader" | "chat"
  const [chapterIdx, setChapterIdx] = useState(0);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);

  // TTS
  const [ttsPlaying, setTtsPlaying] = useState(false);
  const [ttsProgress, setTtsProgress] = useState(0);
  const [ttsLabel, setTtsLabel] = useState("Escuchar");
  const utteranceRef = useRef(null);
  const ttsSupported = typeof window !== "undefined" && "speechSynthesis" in window && typeof SpeechSynthesisUtterance !== "undefined";

  const endRef = useRef(null);
  const inputRef = useRef(null);

  const chapter = BOOK.chapters[chapterIdx];
  const parts = getParts();

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  // Stop TTS when chapter changes
  useEffect(() => {
    stopTTS();
  }, [chapterIdx]);

  const stopTTS = () => {
    if (ttsSupported) window.speechSynthesis.cancel();
    setTtsPlaying(false);
    setTtsProgress(0);
    setTtsLabel("Escuchar");
  };

  const toggleTTS = () => {
    if (!ttsSupported) return;
    if (ttsPlaying) {
      stopTTS();
      return;
    }

    const text = `${chapter.title}. ${chapter.content}`;
    const words = text.split(/\s+/);
    const totalWords = words.length;
    let wordCount = 0;

    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = "es-AR";
    utterance.rate = 0.92;
    utterance.pitch = 1.0;

    // Prefer es-AR, then latam, then any Spanish voice
    const assignVoice = () => {
      const voices = window.speechSynthesis.getVoices();
      const chosen = voices.find(v => v.lang === "es-AR")
        || voices.find(v => ["es-419","es-US","es-MX"].includes(v.lang))
        || voices.find(v => v.lang.startsWith("es"));
      if (chosen) utterance.voice = chosen;
    };
    if (window.speechSynthesis.getVoices().length > 0) {
      assignVoice();
    } else {
      window.speechSynthesis.onvoiceschanged = () => { assignVoice(); window.speechSynthesis.onvoiceschanged = null; };
    }

    utterance.onboundary = (e) => {
      if (e.name === "word") {
        wordCount++;
        const pct = Math.min((wordCount / totalWords) * 100, 100);
        setTtsProgress(pct);
        const mins = Math.floor(((totalWords - wordCount) / 150));
        setTtsLabel(mins > 0 ? `~${mins} min` : "Terminando...");
      }
    };

    utterance.onend = () => {
      setTtsPlaying(false);
      setTtsProgress(100);
      setTtsLabel("Listo ✓");
      setTimeout(() => { setTtsProgress(0); setTtsLabel("Escuchar"); }, 2000);
    };

    utterance.onerror = () => stopTTS();

    utteranceRef.current = utterance;
    window.speechSynthesis.speak(utterance);
    setTtsPlaying(true);
    setTtsLabel("Reproduciendo...");
  };

  const sendMessage = async (text = input) => {
    const msg = text.trim();
    if (!msg || loading) return;
    setInput("");
    const newMsgs = [...messages, { role: "user", content: msg, time: fmtTime() }];
    setMessages(newMsgs);
    setLoading(true);

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "anthropic-version": "2023-06-01",
          "anthropic-dangerous-direct-browser-access": "true"
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 1000,
          system: SYSTEM_PROMPT,
          messages: newMsgs.map(m => ({ role: m.role, content: m.content }))
        })
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);
      const reply = data.content?.map(b => b.text || "").join("") || "Sin respuesta.";
      setMessages(prev => [...prev, { role: "assistant", content: reply, time: fmtTime() }]);
    } catch(err) {
      setMessages(prev => [...prev, { role: "assistant", content: `Error: ${err.message || "Intentá de nuevo"} 🙏`, time: fmtTime() }]);
    }
    setLoading(false);
  };

  const goToChapter = (idx) => {
    setChapterIdx(idx);
    setView("reader");
    setSidebarOpen(false);
  };

  const renderSidebar = () => {
    const partEntries = Object.entries(parts);
    return (
      <>
        <div className={`sidebar-overlay ${sidebarOpen ? "open" : ""}`} onClick={() => setSidebarOpen(false)} />
        <aside className={`sidebar ${sidebarOpen ? "open" : ""}`}>
          <div className="sidebar-head" style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <span>📖 Capítulos</span>
            <button onClick={() => setSidebarOpen(false)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 18, color: "var(--muted)", lineHeight: 1 }}>✕</button>
          </div>
        <div className="chapter-list">
          {partEntries.map(([partName, chs]) => (
            <div key={partName}>
              <div className="part-label">{partName.replace("Parte ", "Pt. ")}</div>
              {chs.map(ch => (
                <button
                  key={ch.id}
                  className={`ch-btn ${ch.id === chapterIdx ? "active" : ""}`}
                  onClick={() => goToChapter(ch.id)}
                >
                  <span className="ch-num">{ch.id === 0 ? "📖" : ch.id}</span>
                  <span style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{ch.title}</span>
                </button>
              ))}
            </div>
          ))}
        </div>
        </aside>
      </>
    );
  };

  return (
    <>
      <style>{css}</style>
      <div className="app">
        {/* HEADER */}
        <header className="header">
          <div className="logo-wrap">
            <div className="logo-icon">
              {LOGO_URL
                ? <img src={LOGO_URL} alt="Logo" style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: 11 }} />
                : "🍪"}
            </div>
            <div>
              <div className="logo-title">La Fábrica Viral</div>
              <div className="logo-sub">Tu sistema para vender desde cero</div>
            </div>
          </div>
          <button className="menu-toggle" onClick={() => setSidebarOpen(o => !o)}>☰</button>
          <div className="tab-bar">
            <button className={`tab-btn ${view === "reader" ? "active" : ""}`} onClick={() => setView("reader")}>
              📖 Leer
            </button>
            <button className={`tab-btn ${view === "chat" ? "active" : ""}`} onClick={() => setView("chat")}>
              💬 Preguntarle a la IA
            </button>
          </div>
        </header>

        <div className="main">
          {renderSidebar()}

          {/* READER VIEW */}
          {view === "reader" && (
            <div className="reader">
              <div className="reader-content">
                <div className="chapter-part">{chapter.part}</div>
                <div className="chapter-title">{chapter.title}</div>
                <div className="chapter-body">{chapter.content}</div>
                <div style={{ height: 40 }} />
              </div>

              {/* TTS + NAV BAR */}
              <div style={{ borderTop: "1px solid var(--border)", background: "var(--surface)", flexShrink: 0 }}>
                <div className="tts-bar">
                  {ttsSupported ? (
                    <>
                      <button className="tts-btn" onClick={toggleTTS}>
                        {ttsPlaying ? "⏹" : "▶"}
                      </button>
                      <div className="tts-progress">
                        <div className="tts-progress-bar" style={{ width: `${ttsProgress}%` }} />
                      </div>
                      <span className="tts-label">{ttsLabel}</span>
                    </>
                  ) : (
                    <span className="tts-notice">🔇 Audio no disponible — probá Chrome en Android</span>
                  )}

                  <div className="nav-btns">
                    <button className="nav-btn" onClick={() => setChapterIdx(i => Math.max(0, i - 1))} disabled={chapterIdx === 0}>←</button>
                    <button className="nav-btn" onClick={() => setChapterIdx(i => Math.min(BOOK.chapters.length - 1, i + 1))} disabled={chapterIdx === BOOK.chapters.length - 1}>→</button>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* CHAT VIEW */}
          {view === "chat" && (
            <div className="chat-panel">
              <div className="messages">
                {messages.length === 0 && (
                  <div className="welcome">
                    <span className="welcome-emoji">🍪</span>
                    <h2>¡Hola! Soy el asistente del libro</h2>
                    <p>Puedo responder cualquier pregunta sobre <strong>La Fábrica Viral</strong>: recetas, estrategias de venta, precios, redes sociales, mentalidad emprendedora y más.</p>
                    <div className="chips">
                      {["¿Por dónde empiezo?", "¿Cuánto cobrar por mis Cookie Fries?", "¿Qué es el reversionado?", "Dame ideas de combos para vender más"].map(q => (
                        <button key={q} className="chip" onClick={() => sendMessage(q)}>{q}</button>
                      ))}
                    </div>
                  </div>
                )}

                {messages.map((m, i) => (
                  <div key={i} className={`msg ${m.role}`}>
                    <div className="msg-ava">{m.role === "user" ? "👤" : "🍪"}</div>
                    <div>
                      <div className="msg-bubble">{m.content}</div>
                      <div style={{ fontSize: 10, color: "var(--dim)", marginTop: 4, padding: "0 4px", textAlign: m.role === "user" ? "right" : "left" }}>{m.time}</div>
                    </div>
                  </div>
                ))}

                {loading && (
                  <div className="msg assistant">
                    <div className="msg-ava">🍪</div>
                    <div className="msg-bubble" style={{ padding: 0 }}>
                      <div className="typing"><div className="tdot"/><div className="tdot"/><div className="tdot"/></div>
                    </div>
                  </div>
                )}
                <div ref={endRef} />
              </div>

              <div className="quick-section">
                <div className="quick-label">Preguntas frecuentes</div>
                <div className="quick-row">
                  {QUICK_ACTIONS.map(a => (
                    <button key={a.label} className="quick-pill" onClick={() => sendMessage(a.prompt)} disabled={loading}>
                      {a.icon} {a.label}
                    </button>
                  ))}
                </div>
              </div>

              <div className="input-zone">
                <div className="input-box">
                  <textarea
                    ref={inputRef}
                    className="chat-input"
                    placeholder="Preguntame lo que quieras sobre el libro..."
                    value={input} rows={1}
                    onChange={e => setInput(e.target.value)}
                    onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
                  />
                  <button className="send-btn" onClick={() => sendMessage()} disabled={loading || !input.trim()}>↑</button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </>
  );
}
